  ('heelevel3-5ff21eeb-moex-00114', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '按稅捐稽徵法之規定，下列關於退稅之敘述，何者正確？①納稅義務人因自行計算錯誤導致溢繳', '["因地政機關將土地面積登記 錯誤，導致納稅義務人溢繳地價稅款，納稅義務人得自繳納之日起 15 年間提出申請退還溢繳稅 款", "納稅義務人因自行計算錯誤，申請溢繳稅款之退還，按各年度1月1日郵政儲金1年期定 存儲金固定利率，按日加計利息一併退還", "納稅義務人因開立不實發票而虛增銷售額致溢繳營 業稅額，得自繳納之日起10年內請求返還", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00115', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '依所得稅法之規定，下列敘述何者正確？①依現行勞工退休金條例之規定，個人於其薪資數額中', '["個 人參與多層次傳銷，因下層直銷商進貨而抽取之佣金屬執行業務所得", "個人出售其於105年取 得之自住房屋、土地，其財產交易所得應計入綜合所得總額", "個人出售上市股票交易所得須採 分離課稅", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00116', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '依所得稅法及營利事業所得稅查核準則之規定，有關營利事業認列職工退休金的敘述，下列何者 正確？', '["適用勞動基準法之營利事業為委任經理人提繳之退休金，每年度得在不超過當年度已付薪資總 額15%限度內，以費用列支", "營利事業因解散，在計算清算所得時，職工退休金準備之累計餘額，應轉作當年度費用", "營利事業提列之退休金費用申報時，列入薪資支出項目中", "營利事業依勞工退休金條例提繳之勞工退休金，每年度得在不超過當年度已付薪資總額 8%限 度內，以費用列支"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00117', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-113-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '王大明為居住者，於105年7月1日購入A屋，房地成本1,000萬元，供作自住使用，並設立戶 籍，嗣於112年5月1日將該自住房地出售，售價1,600萬元，繳納土地增值稅30萬元，無提示 其他相關費用。又於113年2月1日購入B屋供自住使用，房地總成本1,200萬元。請問王大明 得申請重購自住房地退稅的金額為多少？', '["0元", "105,000元", "114,000元", "127,500元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "c30b10e411eb", "answer_pdf_sha1": "074011d2d687", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "320", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
